content.text:
I have created a fully collaborative, real-time synchronized Kanban board for Project Ollie, built in strict adherence to the Polaris Design System and Material Design 3 guidelines. It is pre-populated with realistic tasks assigned to actual workspace team members (Ajay, Belinda, Mirjam, and Simon) and connects directly to the flat-file state synchronization API.

<!-- index.html -->
```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Ollie Workspace Kanban Board</title>
  <!-- Google Fonts & Tailwind CSS -->
  <link href="https://fonts.googleapis.com/css2?family=Google+Sans:wght@400;500;700&family=Google+Sans+Text:wght@400;500&display=swap" rel="stylesheet">
  <script src="https://cdn.tailwindcss.com"></script>
  <script>
    tailwind.config = {
      theme: {
        extend: {
          fontFamily: {
            sans: ['"Google Sans"', 'sans-serif'],
            text: ['"Google Sans Text"', 'sans-serif'],
          }
        }
      }
    }
  </script>
  <style>
    :root {
      --gemini-rail-icon-gap: 0px;
      --gemini-side-panel-padding-left: 16px;
      --gemini-side-panel-padding-right: 16px;
      --gemini-header-padding-left: 10px;
      --gemini-header-padding-right: 12px;
      --gemini-header-elements-gap: 8px;
    }
    body {
      font-family: "Google Sans Text", sans-serif;
      background-color: #ffffff;
    }
    .google-sans-heading {
      font-family: "Google Sans", sans-serif;
    }
    /* Simple smooth transitions for dragging */
    .drag-over {
      background-color: #e3ecf7 !important;
      border-color: #0b57d0 !important;
    }
  </style>
</head>
<body class="p-6 min-h-screen text-slate-800 flex flex-col items-center">

  <!-- Core Content Container -->
  <div class="w-full max-w-7xl flex flex-col gap-6">

    <!-- Polaris-Compliant Minimal Control Row (No Redundant Header Banners) -->
    <div class="flex flex-col sm:flex-row sm:items-center justify-between gap-4 w-full">
      <div class="flex items-center gap-3 flex-wrap">
        <input 
          type="text" 
          id="search-input" 
          placeholder="Search tasks..." 
          oninput="handleSearchFilter()"
          class="px-4 py-2 bg-[#f0f4f9] rounded-full border border-transparent focus:border-[#0b57d0] focus:bg-white outline-none font-text text-sm w-64 transition-all"
        >
        <select 
          id="filter-assignee" 
          onchange="handleSearchFilter()"
          class="px-4 py-2 bg-[#f0f4f9] rounded-full border border-transparent focus:border-[#0b57d0] focus:bg-white outline-none font-text text-sm transition-all"
        >
          <option value="all">All Assignees</option>
          <option value="yadavajay@google.com">Ajay Yadav</option>
          <option value="belindapreno@google.com">Belinda Preno</option>
          <option value="mirjamvanesch@google.com">Mirjam van Esch</option>
          <option value="simonsok@google.com">Simon Sok</option>
        </select>
      </div>

      <button 
        onclick="openAddTaskModal()" 
        class="flex items-center gap-2 px-5 py-2.5 bg-[#0b57d0] text-white rounded-full font-sans text-sm font-medium hover:bg-[#0842a0] transition-all shadow-sm self-start sm:self-auto"
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line></svg>
        Add Task
      </button>
    </div>

    <!-- 3-Column Kanban Layout -->
    <div class="grid grid-cols-1 md:grid-cols-3 gap-6 w-full items-start">

      <!-- TO DO Column -->
      <div 
        id="col-todo" 
        class="bg-[#f0f4f9] rounded-2xl p-4 border border-[#747775]/20 flex flex-col gap-4 min-h-[500px] transition-colors duration-200"
        ondragover="allowDrop(event)"
        ondragenter="handleDragEnter(event, 'col-todo')"
        ondragleave="handleDragLeave(event, 'col-todo')"
        ondrop="drop(event, 'todo')"
      >
        <div class="flex items-center justify-between px-2 py-1">
          <h2 class="google-sans-heading text-sm font-medium text-slate-800">To Do</h2>
          <span id="count-todo" class="text-xs bg-white text-slate-500 font-medium px-2 py-0.5 rounded-full border border-[#747775]/20">0</span>
        </div>
        <div id="tasks-todo" class="flex flex-col gap-3 min-h-[400px]"></div>
      </div>

      <!-- IN PROGRESS Column -->
      <div 
        id="col-in_progress" 
        class="bg-[#f0f4f9] rounded-2xl p-4 border border-[#747775]/20 flex flex-col gap-4 min-h-[500px] transition-colors duration-200"
        ondragover="allowDrop(event)"
        ondragenter="handleDragEnter(event, 'col-in_progress')"
        ondragleave="handleDragLeave(event, 'col-in_progress')"
        ondrop="drop(event, 'in_progress')"
      >
        <div class="flex items-center justify-between px-2 py-1">
          <h2 class="google-sans-heading text-sm font-medium text-slate-800">In Progress</h2>
          <span id="count-in_progress" class="text-xs bg-white text-slate-500 font-medium px-2 py-0.5 rounded-full border border-[#747775]/20">0</span>
        </div>
        <div id="tasks-in_progress" class="flex flex-col gap-3 min-h-[400px]"></div>
      </div>

      <!-- DONE Column -->
      <div 
        id="col-done" 
        class="bg-[#f0f4f9] rounded-2xl p-4 border border-[#747775]/20 flex flex-col gap-4 min-h-[500px] transition-colors duration-200"
        ondragover="allowDrop(event)"
        ondragenter="handleDragEnter(event, 'col-done')"
        ondragleave="handleDragLeave(event, 'col-done')"
        ondrop="drop(event, 'done')"
      >
        <div class="flex items-center justify-between px-2 py-1">
          <h2 class="google-sans-heading text-sm font-medium text-slate-800">Done</h2>
          <span id="count-done" class="text-xs bg-white text-slate-500 font-medium px-2 py-0.5 rounded-full border border-[#747775]/20">0</span>
        </div>
        <div id="tasks-done" class="flex flex-col gap-3 min-h-[400px]"></div>
      </div>

    </div>
  </div>

  <!-- ADD / EDIT TASK MODAL -->
  <div id="task-modal" class="fixed inset-0 bg-black/40 backdrop-blur-[1px] flex items-center justify-center hidden z-50 p-4">
    <div class="bg-white rounded-3xl p-6 border border-[#747775]/20 max-w-md w-full flex flex-col gap-4 shadow-xl">
      <div class="flex justify-between items-center">
        <h3 id="modal-title" class="google-sans-heading text-lg font-medium text-slate-950">Add New Task</h3>
        <button onclick="closeModal()" class="text-slate-400 hover:text-slate-600">
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line></svg>
        </button>
      </div>

      <form id="task-form" onsubmit="handleFormSubmit(event)" class="flex flex-col gap-4">
        <input type="hidden" id="task-id">

        <div>
          <label class="block text-xs font-medium text-slate-500 mb-1">Title</label>
          <input 
            type="text" 
            id="modal-task-title" 
            required 
            placeholder="What needs to be done?" 
            class="w-full px-3 py-2 bg-[#f0f4f9] rounded-xl border border-transparent focus:border-[#0b57d0] focus:bg-white outline-none font-text text-sm transition-all"
          >
        </div>

        <div>
          <label class="block text-xs font-medium text-slate-500 mb-1">Description</label>
          <textarea 
            id="modal-task-desc" 
            rows="3" 
            placeholder="Provide context or details..." 
            class="w-full px-3 py-2 bg-[#f0f4f9] rounded-xl border border-transparent focus:border-[#0b57d0] focus:bg-white outline-none font-text text-sm transition-all resize-none"
          ></textarea>
        </div>

        <div class="grid grid-cols-2 gap-4">
          <div>
            <label class="block text-xs font-medium text-slate-500 mb-1">Assignee</label>
            <select 
              id="modal-task-assignee" 
              class="w-full px-3 py-2 bg-[#f0f4f9] rounded-xl border border-transparent focus:border-[#0b57d0] focus:bg-white outline-none font-text text-sm transition-all"
            >
              <option value="">Unassigned</option>
              <option value="yadavajay@google.com">Ajay Yadav</option>
              <option value="belindapreno@google.com">Belinda Preno</option>
              <option value="mirjamvanesch@google.com">Mirjam van Esch</option>
              <option value="simonsok@google.com">Simon Sok</option>
            </select>
          </div>

          <div>
            <label class="block text-xs font-medium text-slate-500 mb-1">Priority</label>
            <select 
              id="modal-task-priority" 
              class="w-full px-3 py-2 bg-[#f0f4f9] rounded-xl border border-transparent focus:border-[#0b57d0] focus:bg-white outline-none font-text text-sm transition-all"
            >
              <option value="P0">P0 (Blocker)</option>
              <option value="P1">P1 (High)</option>
              <option value="P2" selected>P2 (Normal)</option>
              <option value="P3">P3 (Low)</option>
              <option value="P4">P4 (Wishlist)</option>
            </select>
          </div>
        </div>

        <div>
          <label class="block text-xs font-medium text-slate-500 mb-1">Column Status</label>
          <select 
            id="modal-task-status" 
            class="w-full px-3 py-2 bg-[#f0f4f9] rounded-xl border border-transparent focus:border-[#0b57d0] focus:bg-white outline-none font-text text-sm transition-all"
          >
            <option value="todo">To Do</option>
            <option value="in_progress">In Progress</option>
            <option value="done">Done</option>
          </select>
        </div>

        <div class="flex items-center justify-between mt-2 pt-2 border-t border-[#747775]/10">
          <button 
            type="button" 
            id="delete-task-btn" 
            onclick="handleDeleteTask()" 
            class="hidden text-red-600 hover:text-red-700 font-sans text-sm font-medium transition-colors"
          >
            Delete Task
          </button>
          <div class="flex gap-2 ml-auto">
            <button 
              type="button" 
              onclick="closeModal()" 
              class="px-4 py-2 text-[#0b57d0] font-sans text-sm font-medium hover:bg-[#d3e3fd]/40 rounded-full transition-all"
            >
              Cancel
            </button>
            <button 
              type="submit" 
              class="px-5 py-2 bg-[#0b57d0] text-white font-sans text-sm font-medium hover:bg-[#0842a0] rounded-full transition-all"
            >
              Save
            </button>
          </div>
        </div>
      </form>
    </div>
  </div>

  <script>
    // Real Workspace Team Members
    const TEAM_MEMBERS = {
      "yadavajay@google.com": {
        name: "Ajay Yadav",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW5ytDzOzOxOMnVKGMTlZFIQFZGQE-F3hF9WT2C3_8rKFkSa6V4xQ=s64"
      },
      "belindapreno@google.com": {
        name: "Belinda Preno",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW8kkayF4FN3ib50ZpJsNFIMcSF9CLOgEcXNjlG9yhQ2xy1dL2q=s64"
      },
      "mirjamvanesch@google.com": {
        name: "Mirjam van Esch",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjXTBbC9f6t0nk1AnwJs5rlbhjpfVQxK2sM8PqQXbNVAx3YKh4LMVA=s64"
      },
      "simonsok@google.com": {
        name: "Simon Sok",
        avatar: "https://lh3.googleusercontent.com/a-/ALV-UjUJwa8yeHprZ88_pXXGVlN6TT1mDyU1T8GUcNOixdQ46wyCNDlcGA=s64"
      }
    };

    // Canonical State Model
    let appState = {
      tasks: [
        {
          id: "task-ollie-1",
          title: "Implement ScaNN vector index in Tasks table",
          description: "Set up the native approximate nearest neighbor vector index on Tasks table in Spanner with COSINE distance metrics.",
          status: "todo",
          assignee: "yadavajay@google.com",
          priority: "P1"
        },
        {
          id: "task-ollie-2",
          title: "Design Wiz UI Task Board for Ollie FE",
          description: "Build the interactive, real-time workspace board view on Google Wiz UI framework following WDS principles.",
          status: "in_progress",
          assignee: "belindapreno@google.com",
          priority: "P0"
        },
        {
          id: "task-ollie-3",
          title: "Verify Task Service Protobuf gRPC APIs",
          description: "Develop integration tests for CreateTask, GetTaskTree, and IngestExternalEvents RPC contracts.",
          status: "done",
          assignee: "simonsok@google.com",
          priority: "P2"
        },
        {
          id: "task-ollie-4",
          title: "Integrate Memory Reflection Hook in Sobi Harness",
          description: "Add background listener triggering Gemini distillation on finished trajectories to save permanent memory facts.",
          status: "todo",
          assignee: "mirjamvanesch@google.com",
          priority: "P1"
        }
      ]
    };

    // Shared State Management Endpoints
    const envId = window.__sandboxEnvId || null;
    const syncKey = "ollie_kanban_board_state";

    async function loadSyncedState() {
      if (!envId) return;
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data && Array.isArray(json.data.tasks)) {
          const currentString = JSON.stringify(appState);
          const incomingString = JSON.stringify(json.data);
          if (currentString !== incomingString) {
            appState = json.data;
            renderBoard();
          }
        }
      } catch (err) {
        console.error("Failed to load synced state:", err);
      }
    }

    async function saveSyncedState() {
      if (envId) {
        try {
          await fetch(`/api/sync/${envId}/${syncKey}`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ data: appState })
          });
        } catch (err) {
          console.error("Failed to save synced state:", err);
        }
      } else {
        localStorage.setItem(syncKey, JSON.stringify(appState));
      }
    }

    // Drag and Drop Controllers
    function allowDrop(ev) {
      ev.preventDefault();
    }

    function handleDragEnter(ev, colId) {
      document.getElementById(colId).classList.add("drag-over");
    }

    function handleDragLeave(ev, colId) {
      const colEl = document.getElementById(colId);
      // Ensure we only leave when exiting the column container itself
      if (!colEl.contains(ev.relatedTarget)) {
        colEl.classList.remove("drag-over");
      }
    }

    function drag(ev) {
      ev.dataTransfer.setData("text/plain", ev.currentTarget.id);
      ev.currentTarget.classList.add("opacity-30");
    }

    function dragEnd(ev) {
      ev.currentTarget.classList.remove("opacity-30");
    }

    async function drop(ev, targetStatus) {
      ev.preventDefault();

      // Clean up column hover highlight styles
      document.getElementById("col-todo").classList.remove("drag-over");
      document.getElementById("col-in_progress").classList.remove("drag-over");
      document.getElementById("col-done").classList.remove("drag-over");

      const cardId = ev.dataTransfer.getData("text/plain");
      const taskId = cardId.replace("card-", "");

      const task = appState.tasks.find(t => t.id === taskId);
      if (task && task.status !== targetStatus) {
        task.status = targetStatus;
        renderBoard();
        await saveSyncedState();
      }
    }

    // Interactive Filters
    function handleSearchFilter() {
      renderBoard();
    }

    // Render Mechanism
    function renderBoard() {
      const searchQuery = document.getElementById("search-input").value.toLowerCase();
      const assigneeFilter = document.getElementById("filter-assignee").value;

      const columns = {
        todo: document.getElementById("tasks-todo"),
        in_progress: document.getElementById("tasks-in_progress"),
        done: document.getElementById("tasks-done")
      };

      // Reset columns
      columns.todo.innerHTML = "";
      columns.in_progress.innerHTML = "";
      columns.done.innerHTML = "";

      const counts = { todo: 0, in_progress: 0, done: 0 };

      appState.tasks.forEach(task => {
        // Apply Filters
        const matchesSearch = task.title.toLowerCase().includes(searchQuery) || task.description.toLowerCase().includes(searchQuery);
        const matchesAssignee = assigneeFilter === "all" || task.assignee === assigneeFilter;

        if (!matchesSearch || !matchesAssignee) return;

        counts[task.status]++;

        // Build HTML for Card
        const assignee = TEAM_MEMBERS[task.assignee];
        let assigneeHtml = `
          <div class="flex items-center gap-1.5 bg-[#f0f4f9] rounded-full px-2.5 py-1">
            <span class="w-2 h-2 rounded-full bg-slate-300"></span>
            <span class="text-[11px] font-medium text-slate-500 font-sans">Unassigned</span>
          </div>
        `;
        if (assignee) {
          assigneeHtml = `
            <div class="flex items-center gap-2">
              <img src="${assignee.avatar}" alt="${assignee.name}" class="w-5 h-5 rounded-full object-cover">
              <span class="text-xs font-medium text-slate-600 font-sans">${assignee.name}</span>
            </div>
          `;
        }

        // Clean subtle Priority Badge
        let priorityColor = "text-slate-500";
        if (task.priority === "P0" || task.priority === "P1") {
          priorityColor = "text-[#0b57d0]";
        }

        const card = document.createElement("div");
        card.id = `card-${task.id}`;
        card.draggable = true;
        card.className = "bg-white p-4 rounded-xl border border-[#747775]/20 hover:border-[#747775]/50 transition-all cursor-grab active:cursor-grabbing flex flex-col gap-3 shadow-[0_1px_2px_rgba(0,0,0,0.02)]";

        // Setup Drag Events
        card.ondragstart = drag;
        card.ondragend = dragEnd;
        card.onclick = (e) => {
          // Avoid opening modal if clicking inside specific action icons
          openEditTaskModal(task.id);
        };

        card.innerHTML = `
          <div class="flex justify-between items-start gap-2">
            <h3 class="font-sans text-[13px] font-medium text-slate-900 leading-tight">${escapeHtml(task.title)}</h3>
            <span class="font-sans text-[11px] font-bold ${priorityColor}">${task.priority}</span>
          </div>
          <p class="font-text text-[12px] text-slate-500 line-clamp-3 leading-relaxed">${escapeHtml(task.description)}</p>
          <div class="flex justify-between items-center mt-1">
            ${assigneeHtml}
            <div class="flex items-center gap-1">
              <button onclick="event.stopPropagation(); shiftTask('${task.id}', 'prev')" class="p-1 hover:bg-[#f0f4f9] rounded-md text-slate-400 hover:text-slate-600 transition-colors" title="Move Left">
                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="19" y1="12" x2="5" y2="12"></line><polyline points="12 19 5 12 12 5"></polyline></svg>
              </button>
              <button onclick="event.stopPropagation(); shiftTask('${task.id}', 'next')" class="p-1 hover:bg-[#f0f4f9] rounded-md text-slate-400 hover:text-slate-600 transition-colors" title="Move Right">
                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="5" y1="12" x2="19" y2="12"></line><polyline points="12 5 19 12 12 19"></polyline></svg>
              </button>
            </div>
          </div>
        `;

        if (columns[task.status]) {
          columns[task.status].appendChild(card);
        }
      });

      // Update Header counts
      document.getElementById("count-todo").innerText = counts.todo;
      document.getElementById("count-in_progress").innerText = counts.in_progress;
      document.getElementById("count-done").innerText = counts.done;
    }

    // Modal Control Orchestrators
    function openAddTaskModal() {
      document.getElementById("modal-title").innerText = "Add New Task";
      document.getElementById("task-id").value = "";
      document.getElementById("task-form").reset();
      document.getElementById("delete-task-btn").classList.add("hidden");
      document.getElementById("task-modal").classList.remove("hidden");
    }

    function openEditTaskModal(id) {
      const task = appState.tasks.find(t => t.id === id);
      if (!task) return;

      document.getElementById("modal-title").innerText = "Edit Task";
      document.getElementById("task-id").value = task.id;
      document.getElementById("modal-task-title").value = task.title;
      document.getElementById("modal-task-desc").value = task.description;
      document.getElementById("modal-task-assignee").value = task.assignee;
      document.getElementById("modal-task-priority").value = task.priority;
      document.getElementById("modal-task-status").value = task.status;

      document.getElementById("delete-task-btn").classList.remove("hidden");
      document.getElementById("task-modal").classList.remove("hidden");
    }

    function closeModal() {
      document.getElementById("task-modal").classList.add("hidden");
    }

    async function handleFormSubmit(event) {
      event.preventDefault();
      const id = document.getElementById("task-id").value;
      const title = document.getElementById("modal-task-title").value;
      const description = document.getElementById("modal-task-desc").value;
      const assignee = document.getElementById("modal-task-assignee").value;
      const priority = document.getElementById("modal-task-priority").value;
      const status = document.getElementById("modal-task-status").value;

      if (id) {
        // Edit Task
        const task = appState.tasks.find(t => t.id === id);
        if (task) {
          task.title = title;
          task.description = description;
          task.assignee = assignee;
          task.priority = priority;
          task.status = status;
        }
      } else {
        // Create Task
        const newTask = {
          id: "task-" + Date.now(),
          title,
          description,
          assignee,
          priority,
          status
        };
        appState.tasks.push(newTask);
      }

      closeModal();
      renderBoard();
      await saveSyncedState();
    }

    async function handleDeleteTask() {
      const id = document.getElementById("task-id").value;
      if (!id) return;

      appState.tasks = appState.tasks.filter(t => t.id !== id);
      closeModal();
      renderBoard();
      await saveSyncedState();
    }

    async function shiftTask(id, direction) {
      const task = appState.tasks.find(t => t.id === id);
      if (!task) return;

      const order = ["todo", "in_progress", "done"];
      let index = order.indexOf(task.status);
      if (direction === "next" && index < 2) {
        task.status = order[index + 1];
      } else if (direction === "prev" && index > 0) {
        task.status = order[index - 1];
      }

      renderBoard();
      await saveSyncedState();
    }

    // Safety escaping
    function escapeHtml(str) {
      if (!str) return "";
      return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#039;");
    }

    // State Synchronization Hooks
    async function init() {
      if (!envId) {
        // Offline / LocalStorage Preview Fallback
        const local = localStorage.getItem(syncKey);
        if (local) {
          try {
            appState = JSON.parse(local);
          } catch (e) {
            console.error(e);
          }
        }
      } else {
        await loadSyncedState();
        setInterval(loadSyncedState, 2000);
      }
      renderBoard();
    }

    init();
  </script>
</body>
</html>
```

