2.5 Memory Service
2.5.1 Authoritative Responsibilities & Operational Scope
* Tiered Tenancy Isolation: Enforces strict logical and cryptographic separation across four memory tiers:
   1. Private Tier (MEMORY_TIER_PRIVATE): Accessible exclusively by the individual human Gaia ID and their Personal Agent.
   2. Workstream Tier (MEMORY_TIER_WORKSTREAM): Shared across all teammates and agent runtimes bound to a specific workstream.
   3. Team / Organization Tier (MEMORY_TIER_TEAM): Cross-workstream organizational knowledge, shared architectural patterns, and verified debugging recipes.
   4. Global Tier (MEMORY_TIER_GLOBAL): System-wide immutable Google3 engineering conventions, style guides, and baseline facts.
* ACL Gatekeeping & HITL Consent: Gating all read and write operations behind verified tokens in MemoryACLs, enforcing human sign-off for team/global memory modifications.
2.5.2 Primary RPC Interfaces & Method Contracts
syntax = "proto3";
package google.workspace.ollie.v1;


import "google/protobuf/timestamp.proto";


service MemoryService {
  rpc CreateMemoryStore(CreateMemoryStoreRequest) returns (MemoryStore);
  rpc WriteMemory(WriteMemoryRequest) returns (FactualFact);
  rpc QueryMemory(QueryMemoryRequest) returns (QueryMemoryResponse);
  rpc VerifyMemoryACL(VerifyACLRequest) returns (VerifyACLResponse);
  rpc SupersedeFact(SupersedeFactRequest) returns (FactualFact);
  rpc ProposeConsensusFact(ProposeConsensusRequest) returns (FactualFact);
}


enum MemoryTier {
  MEMORY_TIER_UNSPECIFIED = 0;
  MEMORY_TIER_PRIVATE = 1;
  MEMORY_TIER_WORKSTREAM = 2;
  MEMORY_TIER_TEAM = 3;
  MEMORY_TIER_GLOBAL = 4;
}


message MemoryStore {
  string store_id = 1;
  MemoryTier tier = 2;
  string scope_id = 3; // gaia_id, workstream_id, team_id, or "GLOBAL"
  string display_name = 4;
  google.protobuf.Timestamp create_time = 5;
}


message CreateMemoryStoreRequest {
  MemoryTier tier = 1;
  string scope_id = 2;
  string display_name = 3;
}


message FactualFact {
  string store_id = 1;
  string fact_id = 2;
  string title = 3;
  string factual_content = 4;
  string fact_category = 5; // ARCHITECTURE, WINNING_STRATEGY, GOTCHA, USER_PREFERENCE
  repeated float vector_embedding = 6; // 768-dim SCANN embedding
  repeated string source_provenance_uris = 7; // URIs: task://123, cl://456, sponge://789
  string status = 8; // ACTIVE, SUPERSEDED, CONSENSUS_PENDING, DELETED
  string superseded_by_fact_id = 9;
  string author_identity = 10;
  float confidence_score = 11;
  google.protobuf.Timestamp create_time = 12;
  google.protobuf.Timestamp update_time = 13;
}


message WriteMemoryRequest {
  string store_id = 1;
  string title = 2;
  string factual_content = 3;
  string fact_category = 4;
  repeated string source_provenance_uris = 5;
  string actor_identity = 6;
}


message QueryMemoryRequest {
  repeated string store_ids = 1; // Ordered search hierarchy
  string query_text = 2;
  int32 max_results = 3;
  float min_similarity_threshold = 4;
  string actor_identity = 5;
  bool include_superseded = 6;
}


message QueryMemoryResponse {
  repeated MemorySearchResult results = 1;
}


message MemorySearchResult {
  FactualFact fact = 1;
  float relevance_score = 2;
  string source_store_id = 3;
}


message VerifyACLRequest {
  string store_id = 1;
  string grantee_identity = 2;
  bool is_write = 3;
}


message VerifyACLResponse {
  bool allowed = 1;
  bool require_hitl_for_write = 2;
}


message SupersedeFactRequest {
  string store_id = 1;
  string old_fact_id = 2;
  string new_fact_id = 3;
}


