  require_hitl_for_write BOOL NOT NULL DEFAULT (true),
  is_revoked BOOL NOT NULL DEFAULT (false),
  granted_by_gaia_id STRING(64) NOT NULL,
  create_time TIMESTAMP NOT NULL OPTIONS (allow_commit_timestamp=true)
) PRIMARY KEY (store_id, grantee_identity, permission_token),
  INTERLEAVE IN PARENT MemoryStores ON DELETE CASCADE;


